import React, { useState } from 'react';
import accessService from '../services/accessService';
import { useNavigate } from 'react-router-dom';
function RequestAccess(){
  const [form,setForm]=useState({fileId:'', ownerEmail:'', role:'read', message:''});
  const navigate=useNavigate();
  const submit=async(e)=>{ e.preventDefault(); try{ await accessService.requestAccess(form); alert('Request sent'); navigate('/dashboard'); }catch(e){ alert('Failed'); } };
  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">Request Access</h2>
      <form onSubmit={submit} className="space-y-3">
        <input required placeholder="File ID" value={form.fileId} onChange={e=>setForm({...form,fileId:e.target.value})} className="w-full p-2 border rounded"/>
        <input required placeholder="Owner Email" value={form.ownerEmail} onChange={e=>setForm({...form,ownerEmail:e.target.value})} className="w-full p-2 border rounded"/>
        <select value={form.role} onChange={e=>setForm({...form,role:e.target.value})} className="w-full p-2 border rounded"><option value="read">Read</option><option value="write">Write</option><option value="download">Download</option><option value="share">Share</option></select>
        <textarea placeholder="Message (optional)" value={form.message} onChange={e=>setForm({...form,message:e.target.value})} className="w-full p-2 border rounded"></textarea>
        <button className="bg-blue-600 text-white px-4 py-2 rounded">Send Request</button>
      </form>
    </div>
  );
}
export default RequestAccess;
